  23→const extractBearerToken = (authHeader = "") => {
  24→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
  25→    if (!trimmed) return "";
  26→
  27→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
  28→    if (bearerMatch?.[1]) {
  29→        return bearerMatch[1].trim();
  30→    }
  31→
  32→    return trimmed;
  33→};
  34→
  35→const resolveAuthUser = async (token) => {
  36→    if (!token) {
  37→        return { user: null, error: null };
  38→    }
  39→
  40→    const { data: authData, error: authError } = await supabase.auth.getUser(token);
  41→    if (authError || !authData?.user?.id) {
  42→        return { user: null, error: authError || new Error("missing user id") };
  43→    }
  44→
  45→    return { user: authData.user, error: null };
  46→};
  47→
  48→const requireAuth = async (req, res, next) => {
  49→    const token = extractBearerToken(req.headers?.authorization);
  50→    if (!token) {
  51→        return res.status(401).json({ error: 'not authorized' });
  52→    }
  53→
  54→    const { user, error } = await resolveAuthUser(token);
  55→    if (error || !user?.id) {
  56→        console.error('auth middleware error:', error?.message || 'missing user id');
  57→        return res.status(401).json({ error: 'not authorized' });
  58→    }
  59→
  60→    req.userId = user.id;
  61→    req.authUser = user;
  62→    return next();
  63→};
  64→
  65→const optionalAuth = async (req, _res, next) => {
  66→    const token = extractBearerToken(req.headers?.authorization);
  67→    if (!token) {
  68→        return next();
  69→    }
  70→
  71→    const { user } = await resolveAuthUser(token);
  72→    if (user?.id) {
  73→        req.userId = user.id;
  74→        req.authUser = user;
  75→    }
  76→
  77→    return next();
  78→};
