```js
const runPulseAnimation = (node) => {
    const originalRadius = node.radius();
    new Konva.Tween({
        node,
        duration: 0.3,
        scaleX: 1.8,
        scaleY: 1.8,
        shadowBlur: 30,
        easing: Konva.Easings.EaseOut,
        onFinish: () => {
