router.get('/universe/posts', optionalAuth, async (req, res) => {
    const { minX, minY, maxX, maxY, limit = 200 } = req.query;

    // Validate bounding box
    const fMinX = parseFloat(minX);
    const fMinY = parseFloat(minY);
    const fMaxX = parseFloat(maxX);
    const fMaxY = parseFloat(maxY);
    const parsedLimit = Math.min(Math.max(parseInt(limit) || 200, 1), 500);

    if ([fMinX, fMinY, fMaxX, fMaxY].some(v => !Number.isFinite(v))) {
        return res.status(400).json({ error: 'minX, minY, maxX, maxY must be finite numbers' });
    }

    try {
        const { data, error } = await supabase
            .from('journals')
            .select(`
                id, title, content, post_type, canvas_doc, created_at,
                universe_x, universe_y,
                users(id, name, image_url, badge),
                like_count: likes(count)
            `)
            .eq('privacy', 'public')
            .not('universe_x', 'is', null)
            .not('universe_y', 'is', null)
            .gte('universe_x', fMinX)
            .lte('universe_x', fMaxX)
            .gte('universe_y', fMinY)
            .lte('universe_y', fMaxY)
            .order('created_at', { ascending: false })
            .limit(parsedLimit);

        if (error) {
            console.error('universe posts query error:', error.message);
            return res.status(500).json({ error: 'failed to fetch universe posts' });
        }

        return res.status(200).json({ data: data || [] });
    } catch (err) {
        console.error('universe posts error:', err);
        return res.status(500).json({ error: 'internal server error' });
    }
});
```

Key details:
- Uses `optionalAuth` -- anyone can browse the universe, but if logged in, req.userId is available for future features (e.g., highlighting your own stars).
- Filters for `privacy = 'public'` and both `universe_x` and `universe_y` being non-null.
- Uses Supabase range filters (`gte`/`lte`) for the bounding box query.
- Selects a **lightweight** payload -- no full content needed for stars, but includes `content` and `canvas_doc` for the preview snippet. If performance becomes a concern, these could be truncated server-side.

#### 2E. `server/services/uploadService.js`

