Add a spiral layout helper and a user home coordinate hasher at the top of the file (after the existing imports):

```js
/**
 * Deterministic "home" coordinate for a user, derived from their UUID.
 * Maps to a region in the range [-50000, +50000] for both x and y.
 * This gives each user a unique home position without storing extra columns.
 */
const UNIVERSE_RANGE = 50000;

const simpleHash = (str) => {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        const ch = str.charCodeAt(i);
        hash = ((hash << 5) - hash) + ch;
        hash = hash & hash; // Convert to 32-bit integer
    }
    return hash;
};

const userHomeCoords = (userId) => {
    // Use two halves of the UUID for independent x/y hashing
    const half = Math.floor(userId.length / 2);
    const xHash = simpleHash(userId.slice(0, half));
    const yHash = simpleHash(userId.slice(half));

    // Map to range [-UNIVERSE_RANGE, +UNIVERSE_RANGE]
    const x = ((xHash % UNIVERSE_RANGE) + UNIVERSE_RANGE) % UNIVERSE_RANGE - UNIVERSE_RANGE / 2;
    const y = ((yHash % UNIVERSE_RANGE) + UNIVERSE_RANGE) % UNIVERSE_RANGE - UNIVERSE_RANGE / 2;
    return { x, y };
};

/**
 * Archimedean spiral: each subsequent post is placed further from home.
 * @param {number} index - The 0-based index of this post among the user's posts
 * @returns {{ dx: number, dy: number }} - Offset from home coordinates
 */
const spiralLayout = (index) => {
    if (index === 0) return { dx: 0, dy: 0 };

    const angle = index * 0.8;           // radians per step (golden-angle-ish)
    const radius = 30 * Math.sqrt(index); // grow outward with sqrt for density

    return {
        dx: radius * Math.cos(angle),
        dy: radius * Math.sin(angle),
    };
};
```

Then inside `uploadJournalContentService`, just before the `supabase.from('journals').insert(insertPayload)` call (around line 283), add:

```js
