### 11. SQL Backfill Script for Existing Posts

Existing posts have `universe_x = NULL` and `universe_y = NULL`. A one-time backfill script should be run to populate them. This is best run as a standalone Node.js script or directly via the Supabase SQL editor.

**Option A: Node.js script** (recommended -- uses the same hash/spiral logic):

Create `server/scripts/backfillUniverseCoords.js`:

```js
import supabase from '../services/supabase.js';

const UNIVERSE_RANGE = 50000;

const simpleHash = (str) => {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        const ch = str.charCodeAt(i);
        hash = ((hash << 5) - hash) + ch;
        hash = hash & hash;
    }
    return hash;
};

const userHomeCoords = (userId) => {
    const half = Math.floor(userId.length / 2);
    const xHash = simpleHash(userId.slice(0, half));
    const yHash = simpleHash(userId.slice(half));
    const x = ((xHash % UNIVERSE_RANGE) + UNIVERSE_RANGE) % UNIVERSE_RANGE - UNIVERSE_RANGE / 2;
    const y = ((yHash % UNIVERSE_RANGE) + UNIVERSE_RANGE) % UNIVERSE_RANGE - UNIVERSE_RANGE / 2;
    return { x, y };
};

const spiralLayout = (index) => {
    if (index === 0) return { dx: 0, dy: 0 };
    const angle = index * 0.8;
    const radius = 30 * Math.sqrt(index);
    return {
        dx: radius * Math.cos(angle),
        dy: radius * Math.sin(angle),
    };
};

const backfill = async () => {
    // Fetch all posts without coordinates, ordered by user and creation date
    const { data: posts, error } = await supabase
        .from('journals')
        .select('id, user_id, created_at')
        .is('universe_x', null)
        .order('user_id')
        .order('created_at', { ascending: true });

    if (error) {
        console.error('Failed to fetch posts:', error.message);
        process.exit(1);
    }

    console.log(`Found ${posts.length} posts to backfill`);

    // Group by user
    const byUser = {};
    for (const post of posts) {
        if (!byUser[post.user_id]) byUser[post.user_id] = [];
        byUser[post.user_id].push(post);
    }

    let updated = 0;
    for (const [userId, userPosts] of Object.entries(byUser)) {
        const home = userHomeCoords(userId);

        for (let i = 0; i < userPosts.length; i++) {
            const offset = spiralLayout(i);
            const { error: updateError } = await supabase
                .from('journals')
                .update({
                    universe_x: home.x + offset.dx,
                    universe_y: home.y + offset.dy,
                })
                .eq('id', userPosts[i].id);

            if (updateError) {
                console.error(`Failed to update post ${userPosts[i].id}:`, updateError.message);
            } else {
                updated++;
            }
        }
    }

    console.log(`Backfill complete. Updated ${updated} posts.`);
};

backfill();
```

Run with: `node --experimental-modules server/scripts/backfillUniverseCoords.js`

**Option B: Pure SQL** (simpler but cannot replicate the JS hash exactly):

A SQL-only approach could use `md5(user_id)` to derive coordinates, but it would produce different values than the JS `simpleHash`. For consistency, Option A is strongly recommended.

